solution: class Solution {
public:
    int vowelStrings(vector<string>& words, int left, int right) {
        auto isVowel = [](char c) {
            return c=='a' || c=='e' || c=='i' || c=='o' || c=='u';
        };
        int count = 0;
        for (int i = left; i <= right; ++i) {
            const string& w = words[i];
            if (!w.empty() && isVowel(w.front()) && isVowel(w.back()))
                ++count;
        }
        return count;
    }
};
